import { zodResolver } from '@hookform/resolvers/zod';import { useForm } from 'react-hook-form';import { Button } from '@/components/ui/button';import { contactSchema } from '../schemas';import type { ContactFormValues,SupplierContact } from '../types';const cls='mt-1 h-10 w-full rounded-lg border border-slate-300 bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800';
export const ContactForm=({contact,onSubmit,onCancel,isLoading}:{contact?:SupplierContact|null;onSubmit:(v:ContactFormValues)=>void;onCancel:()=>void;isLoading?:boolean})=>{const {register,handleSubmit,formState:{errors}}=useForm<ContactFormValues>({resolver:zodResolver(contactSchema),mode:'onTouched',defaultValues:contact?{name:contact.name,department:contact.department??'',job_title:contact.job_title??'',phone:contact.phone??'',email:contact.email??'',is_primary:Boolean(contact.is_primary),is_emergency:Boolean(contact.is_emergency),notes:contact.notes??''}:{name:'',department:'',job_title:'',phone:'',email:'',is_primary:false,is_emergency:false,notes:''}});return <form onSubmit={handleSubmit(onSubmit)} className="space-y-4"><div className="grid gap-4 sm:grid-cols-2">{(['name','department','job_title','phone','email'] as const).map(name=><label key={name} className="text-sm font-semibold capitalize">{name.replaceAll('_',' ')}<input type={name==='email'?'email':'text'} {...register(name)} className={cls}/>{errors[name]?<span className="text-xs text-red-600">{errors[name]?.message}</span>:null}</label>)}</div><div className="flex flex-wrap gap-4"><label className="flex items-center gap-2 text-sm"><input type="checkbox" {...register('is_primary')}/> Primary contact</label><label className="flex items-center gap-2 text-sm"><input type="checkbox" {...register('is_emergency')}/> Emergency contact</label></div><label className="block text-sm font-semibold">Notes<textarea {...register('notes')} rows={3} className={`${cls} h-auto py-2`}/></label><div className="flex justify-end gap-2"><Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button><Button type="submit" isLoading={isLoading}>Save Contact</Button></div></form>;};
